import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { getOpenLibraryCoverUrl } from '../services/bookCovers';
import './BookCard.css';

// ── Category themes ───────────────────────────────────────────────────────────
const CATEGORY_THEMES = {
  Fiction:       { from: '#1a0a2e', to: '#4a1d96', accent: '#c4b5fd', pattern: 'fiction'     },
  'Non-Fiction': { from: '#0c1445', to: '#1e3a8a', accent: '#93c5fd', pattern: 'nonfiction'  },
  Science:       { from: '#042f2e', to: '#065f46', accent: '#6ee7b7', pattern: 'science'      },
  History:       { from: '#1c0a00', to: '#7c2d12', accent: '#fdba74', pattern: 'history'      },
  Technology:    { from: '#0f0f2e', to: '#1e1b4b', accent: '#a5b4fc', pattern: 'technology'   },
  Romance:       { from: '#4a0020', to: '#9d174d', accent: '#fbcfe8', pattern: 'romance'      },
  Mystery:       { from: '#0a0a1a', to: '#1e1b4b', accent: '#94a3b8', pattern: 'mystery'      },
  Programming:   { from: '#0a1628', to: '#0f2d4a', accent: '#38bdf8', pattern: 'programming'  },
  Biography:     { from: '#1c1006', to: '#78350f', accent: '#fde68a', pattern: 'biography'    },
  'Self-Help':   { from: '#1a0a00', to: '#9a3412', accent: '#fed7aa', pattern: 'selfhelp'     },
};

const DEFAULT_THEME = { from: '#1e1b4b', to: '#312e81', accent: '#818cf8', pattern: 'fiction' };

function truncate(str, max) {
  if (!str) return '';
  return str.length > max ? str.slice(0, max - 1) + '…' : str;
}

// ── Beautiful SVG Book Cover ──────────────────────────────────────────────────
function BookCoverSVG({ title, author, category, accent, from, to, pattern }) {
  const initial  = (title || 'B')[0].toUpperCase();
  const short    = truncate(title, 20);
  const authorSh = truncate(author, 24);
  const uid      = `${initial}${category}`.replace(/\s/g, '');

  // Split title into lines
  const words = (short || '').split(' ');
  const mid   = Math.ceil(words.length / 2);
  const line1 = words.slice(0, mid).join(' ');
  const line2 = words.slice(mid).join(' ');
  const isSingle = short.length <= 12;

  // Generate unique IDs for gradients
  const bgId      = `bg_${uid}`;
  const shineId   = `shine_${uid}`;
  const overlayId = `ov_${uid}`;
  const spineId   = `sp_${uid}`;

  return (
    <svg viewBox="0 0 200 290" xmlns="http://www.w3.org/2000/svg" width="100%" height="100%" style={{display:'block'}}>
      <defs>
        {/* Main background gradient */}
        <linearGradient id={bgId} x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor={from} />
          <stop offset="100%" stopColor={to} />
        </linearGradient>

        {/* Shine overlay */}
        <linearGradient id={shineId} x1="0%" y1="0%" x2="60%" y2="100%">
          <stop offset="0%"   stopColor="rgba(255,255,255,0.10)" />
          <stop offset="50%"  stopColor="rgba(255,255,255,0.03)" />
          <stop offset="100%" stopColor="rgba(0,0,0,0.2)" />
        </linearGradient>

        {/* Bottom overlay for text readability */}
        <linearGradient id={overlayId} x1="0%" y1="0%" x2="0%" y2="100%">
          <stop offset="0%"   stopColor="rgba(0,0,0,0)" />
          <stop offset="100%" stopColor="rgba(0,0,0,0.85)" />
        </linearGradient>

        {/* Spine gradient */}
        <linearGradient id={spineId} x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%"   stopColor="rgba(0,0,0,0.4)" />
          <stop offset="100%" stopColor="rgba(0,0,0,0)" />
        </linearGradient>

        <clipPath id={`clip_${uid}`}>
          <rect width="200" height="290" rx="3"/>
        </clipPath>
      </defs>

      <g clipPath={`url(#clip_${uid})`}>

        {/* ── Background ── */}
        <rect width="200" height="290" fill={`url(#${bgId})`}/>

        {/* ── Pattern artwork — unique per category ── */}
        {pattern === 'fiction' && (
          <g opacity="0.25">
            {/* Abstract swirling galaxies */}
            <ellipse cx="150" cy="80" rx="70" ry="70" fill="none" stroke={accent} strokeWidth="0.5" opacity="0.5"/>
            <ellipse cx="150" cy="80" rx="50" ry="50" fill="none" stroke={accent} strokeWidth="0.5" opacity="0.6"/>
            <ellipse cx="150" cy="80" rx="30" ry="30" fill="none" stroke={accent} strokeWidth="0.7" opacity="0.7"/>
            <ellipse cx="150" cy="80" rx="15" ry="15" fill={accent} opacity="0.15"/>
            <circle cx="150" cy="80" r="4" fill={accent} opacity="0.5"/>
            {/* Stars */}
            {[[30,40],[60,20],[80,60],[160,30],[180,70],[40,90],[170,110]].map(([x,y],i)=>(
              <circle key={i} cx={x} cy={y} r="1.2" fill={accent} opacity="0.6"/>
            ))}
            {[[50,130],[90,150],[130,120],[160,140]].map(([x,y],i)=>(
              <circle key={i} cx={x} cy={y} r="0.8" fill="white" opacity="0.4"/>
            ))}
          </g>
        )}

        {pattern === 'nonfiction' && (
          <g opacity="0.2">
            {/* Grid of dots — data/knowledge */}
            {Array.from({length:8}).map((_,row)=>
              Array.from({length:6}).map((_,col)=>(
                <circle key={`${row}-${col}`} cx={20+col*32} cy={20+row*32} r="2" fill={accent} opacity="0.7"/>
              ))
            )}
            {/* Connecting lines */}
            <line x1="20" y1="20" x2="180" y2="180" stroke={accent} strokeWidth="0.5" opacity="0.5"/>
            <line x1="20" y1="84" x2="116" y2="180" stroke={accent} strokeWidth="0.5" opacity="0.4"/>
            <line x1="84" y1="20" x2="180" y2="116" stroke={accent} strokeWidth="0.5" opacity="0.4"/>
          </g>
        )}

        {pattern === 'science' && (
          <g opacity="0.22">
            {/* Atom / molecular structure */}
            <ellipse cx="110" cy="100" rx="55" ry="20" fill="none" stroke={accent} strokeWidth="1.2" opacity="0.7"/>
            <ellipse cx="110" cy="100" rx="55" ry="20" fill="none" stroke={accent} strokeWidth="1.2" opacity="0.7"
              transform="rotate(60 110 100)"/>
            <ellipse cx="110" cy="100" rx="55" ry="20" fill="none" stroke={accent} strokeWidth="1.2" opacity="0.7"
              transform="rotate(120 110 100)"/>
            <circle cx="110" cy="100" r="8" fill={accent} opacity="0.4"/>
            <circle cx="110" cy="100" r="4" fill={accent} opacity="0.8"/>
            {/* Orbiting electrons */}
            {[[165,100],[55,100],[110,45],[110,155],[152,67],[68,133]].map(([cx,cy],i)=>(
              <circle key={i} cx={cx} cy={cy} r="3" fill={accent} opacity="0.6"/>
            ))}
          </g>
        )}

        {pattern === 'history' && (
          <g opacity="0.2">
            {/* Columns / architecture */}
            {[30,70,110,150].map((x,i)=>(
              <g key={i}>
                <rect x={x} y="40" width="12" height="130" fill={accent} opacity="0.3" rx="1"/>
                <rect x={x-4} y="35" width="20" height="8" fill={accent} opacity="0.5" rx="1"/>
                <rect x={x-4} y="170" width="20" height="8" fill={accent} opacity="0.5" rx="1"/>
              </g>
            ))}
            <rect x="20" y="178" width="152" height="6" fill={accent} opacity="0.4" rx="2"/>
            {/* Sun/radiance */}
            {Array.from({length:12}).map((_,i)=>{
              const a = (i*30)*Math.PI/180;
              return <line key={i} x1={100+Math.cos(a)*18} y1={20+Math.sin(a)*18}
                x2={100+Math.cos(a)*30} y2={20+Math.sin(a)*30}
                stroke={accent} strokeWidth="1" opacity="0.5"/>;
            })}
            <circle cx="100" cy="20" r="10" fill={accent} opacity="0.3"/>
          </g>
        )}

        {pattern === 'technology' && (
          <g opacity="0.2">
            {/* Circuit board traces */}
            <path d="M10 50 H60 V90 H120 V50 H170" stroke={accent} strokeWidth="1.2" fill="none" opacity="0.7"/>
            <path d="M10 120 H40 V80 H90 V120 H140 V80 H190" stroke={accent} strokeWidth="1.2" fill="none" opacity="0.7"/>
            <path d="M10 160 H80 V140 H160 V180 H80 V200 H30" stroke={accent} strokeWidth="1.2" fill="none" opacity="0.6"/>
            {/* Nodes */}
            {[[60,90],[120,90],[40,80],[90,80],[140,80],[80,140],[160,140],[80,200]].map(([cx,cy],i)=>(
              <g key={i}>
                <circle cx={cx} cy={cy} r="5" fill="none" stroke={accent} strokeWidth="1" opacity="0.8"/>
                <circle cx={cx} cy={cy} r="2" fill={accent} opacity="0.6"/>
              </g>
            ))}
          </g>
        )}

        {pattern === 'romance' && (
          <g opacity="0.22">
            {/* Flowing curves / petals */}
            <path d="M100 60 C130 20, 180 40, 160 80 C140 120, 100 110, 100 60Z" fill={accent} opacity="0.15"/>
            <path d="M100 60 C70 20, 20 40, 40 80 C60 120, 100 110, 100 60Z" fill={accent} opacity="0.15"/>
            <path d="M100 60 C140 90, 160 140, 120 160 C80 180, 70 140, 100 60Z" fill={accent} opacity="0.12"/>
            <path d="M100 60 C60 90, 40 140, 80 160 C120 180, 130 140, 100 60Z" fill={accent} opacity="0.12"/>
            <circle cx="100" cy="60" r="8" fill={accent} opacity="0.4"/>
            {/* Small hearts scattered */}
            {[[40,30],[160,50],[30,120],[170,130],[80,180],[130,170]].map(([x,y],i)=>(
              <circle key={i} cx={x} cy={y} r="2" fill={accent} opacity="0.5"/>
            ))}
          </g>
        )}

        {pattern === 'mystery' && (
          <g opacity="0.2">
            {/* Eye / magnifying glass */}
            <ellipse cx="100" cy="90" rx="60" ry="35" fill="none" stroke={accent} strokeWidth="1.2" opacity="0.6"/>
            <circle cx="100" cy="90" r="18" fill="none" stroke={accent} strokeWidth="1.2" opacity="0.7"/>
            <circle cx="100" cy="90" r="8" fill={accent} opacity="0.3"/>
            <circle cx="100" cy="90" r="3" fill={accent} opacity="0.7"/>
            {/* Radiating mystery lines */}
            {Array.from({length:8}).map((_,i)=>{
              const a = (i*45)*Math.PI/180;
              return <line key={i} x1={100+Math.cos(a)*25} y1={90+Math.sin(a)*25}
                x2={100+Math.cos(a)*55} y2={90+Math.sin(a)*55}
                stroke={accent} strokeWidth="0.6" opacity="0.4"/>;
            })}
            {/* Shadow dots */}
            {[[20,150],[40,170],[60,160],[80,175],[120,165],[150,155],[170,170]].map(([x,y],i)=>(
              <circle key={i} cx={x} cy={y} r="1.5" fill={accent} opacity="0.4"/>
            ))}
          </g>
        )}

        {pattern === 'programming' && (
          <g opacity="0.18">
            {/* Binary tree / node graph */}
            {/* Root */}
            <circle cx="100" cy="35" r="8" fill="none" stroke={accent} strokeWidth="1.2" opacity="0.8"/>
            <circle cx="100" cy="35" r="3" fill={accent} opacity="0.7"/>
            {/* Level 2 */}
            <line x1="100" y1="43" x2="55" y2="73" stroke={accent} strokeWidth="0.8" opacity="0.6"/>
            <line x1="100" y1="43" x2="145" y2="73" stroke={accent} strokeWidth="0.8" opacity="0.6"/>
            <circle cx="55" cy="80" r="7" fill="none" stroke={accent} strokeWidth="1.2" opacity="0.8"/>
            <circle cx="55" cy="80" r="3" fill={accent} opacity="0.6"/>
            <circle cx="145" cy="80" r="7" fill="none" stroke={accent} strokeWidth="1.2" opacity="0.8"/>
            <circle cx="145" cy="80" r="3" fill={accent} opacity="0.6"/>
            {/* Level 3 */}
            <line x1="55" y1="87" x2="28" y2="117" stroke={accent} strokeWidth="0.8" opacity="0.5"/>
            <line x1="55" y1="87" x2="82" y2="117" stroke={accent} strokeWidth="0.8" opacity="0.5"/>
            <line x1="145" y1="87" x2="118" y2="117" stroke={accent} strokeWidth="0.8" opacity="0.5"/>
            <line x1="145" y1="87" x2="172" y2="117" stroke={accent} strokeWidth="0.8" opacity="0.5"/>
            {[[28,124],[82,124],[118,124],[172,124]].map(([cx,cy],i)=>(
              <g key={i}>
                <circle cx={cx} cy={cy} r="6" fill="none" stroke={accent} strokeWidth="1" opacity="0.7"/>
                <circle cx={cx} cy={cy} r="2.5" fill={accent} opacity="0.5"/>
              </g>
            ))}
            {/* Decorative brackets */}
            <text x="14" y="165" fontFamily="monospace" fontSize="28" fill={accent} opacity="0.12" fontWeight="700">{'{ }'}</text>
            <text x="100" y="165" fontFamily="monospace" fontSize="28" fill={accent} opacity="0.12" fontWeight="700">{'[ ]'}</text>
            <text x="50" y="195" fontFamily="monospace" fontSize="16" fill={accent} opacity="0.1">{'( ) => {}'}</text>
          </g>
        )}

        {pattern === 'biography' && (
          <g opacity="0.2">
            {/* Elegant portrait silhouette */}
            <circle cx="100" cy="75" r="32" fill={accent} opacity="0.15"/>
            <circle cx="100" cy="75" r="32" fill="none" stroke={accent} strokeWidth="1.2" opacity="0.5"/>
            <path d="M60 155 C60 120 140 120 140 155" fill={accent} opacity="0.12"/>
            <path d="M60 155 C60 120 140 120 140 155" fill="none" stroke={accent} strokeWidth="1.2" opacity="0.5"/>
            {/* Laurel wreath style */}
            {Array.from({length:10}).map((_,i)=>{
              const a = (i*36-90)*Math.PI/180;
              const r = 42;
              return <ellipse key={i} cx={100+Math.cos(a)*r} cy={75+Math.sin(a)*r}
                rx="5" ry="3" fill={accent} opacity="0.2"
                transform={`rotate(${i*36} ${100+Math.cos(a)*r} ${75+Math.sin(a)*r})`}/>;
            })}
            {/* Horizontal lines — pages/text */}
            {[175,185,195].map((y,i)=>(
              <rect key={i} x="30" y={y} width={140-i*20} height="2" rx="1" fill={accent} opacity="0.25"/>
            ))}
          </g>
        )}

        {pattern === 'selfhelp' && (
          <g opacity="0.22">
            {/* Rising sun / arrow upward */}
            {Array.from({length:10}).map((_,i)=>{
              const a = (i*18)*Math.PI/180;
              return <line key={i} x1={100+Math.cos(a)*35} y1={110+Math.sin(a)*35}
                x2={100+Math.cos(a)*75} y2={110+Math.sin(a)*75}
                stroke={accent} strokeWidth="1" opacity="0.4+i*0.02"/>;
            })}
            <path d="M100 35 L100 110" stroke={accent} strokeWidth="2.5" opacity="0.5" strokeLinecap="round"/>
            <path d="M75 65 L100 35 L125 65" fill="none" stroke={accent} strokeWidth="2.5" opacity="0.6" strokeLinecap="round" strokeLinejoin="round"/>
            <semicircle/>
            <path d="M30 110 A70 70 0 0 1 170 110" fill="none" stroke={accent} strokeWidth="1.5" opacity="0.5"/>
            <circle cx="100" cy="110" r="20" fill={accent} opacity="0.12"/>
            <circle cx="100" cy="110" r="20" fill="none" stroke={accent} strokeWidth="1" opacity="0.4"/>
          </g>
        )}

        {/* ── Shine overlay ── */}
        <rect width="200" height="290" fill={`url(#${shineId})`}/>

        {/* ── Bottom gradient overlay for text ── */}
        <rect width="200" height="290" fill={`url(#${overlayId})`}/>

        {/* ── Spine (left edge) ── */}
        <rect x="0" y="0" width="10" height="290" fill={`url(#${spineId})`}/>
        <rect x="0" y="0" width="4" height="290" fill={accent} opacity="0.6" rx="2"/>

        {/* ── Page edges (right side 3D effect) ── */}
        <rect x="196" y="2" width="2" height="286" fill="rgba(255,255,255,0.05)" rx="1"/>
        <rect x="198" y="4" width="1" height="282" fill="rgba(255,255,255,0.03)"/>

        {/* ── Category badge ── */}
        <rect x="12" y="14" width={Math.min(category.length * 6.5 + 18, 130)} height="18" rx="9"
          fill={accent} opacity="0.22"/>
        <rect x="12" y="14" width={Math.min(category.length * 6.5 + 18, 130)} height="18" rx="9"
          fill="none" stroke={accent} strokeWidth="0.5" opacity="0.5"/>
        <text x="21" y="27" fontFamily="system-ui, sans-serif" fontSize="8.5"
          fontWeight="800" fill={accent} letterSpacing="0.1em">
          {(category || 'BOOK').toUpperCase()}
        </text>

        {/* ── Large decorative initial ── */}
        <text x="105" y="170" textAnchor="middle"
          fontFamily="Georgia, 'Times New Roman', serif"
          fontSize="130" fontWeight="900"
          fill={accent} opacity="0.06" letterSpacing="-8">
          {initial}
        </text>

        {/* ── Title text ── */}
        {isSingle ? (
          <text x="14" y="225"
            fontFamily="Georgia, 'Times New Roman', serif"
            fontSize="17" fontWeight="700"
            fill="#ffffff" letterSpacing="-0.2"
            style={{textShadow:'0 1px 4px rgba(0,0,0,0.8)'}}>
            {short}
          </text>
        ) : (
          <>
            <text x="14" y="218"
              fontFamily="Georgia, 'Times New Roman', serif"
              fontSize="16" fontWeight="700"
              fill="#ffffff" letterSpacing="-0.2">
              {line1}
            </text>
            <text x="14" y="238"
              fontFamily="Georgia, 'Times New Roman', serif"
              fontSize="16" fontWeight="700"
              fill="#ffffff" letterSpacing="-0.2">
              {line2}
            </text>
          </>
        )}

        {/* ── Accent line under title ── */}
        <rect x="14" y="246" width="50" height="1.5" rx="1" fill={accent} opacity="0.8"/>

        {/* ── Author ── */}
        <text x="14" y="264"
          fontFamily="system-ui, sans-serif"
          fontSize="10" fontStyle="italic"
          fill="rgba(255,255,255,0.55)">
          {authorSh}
        </text>

      </g>
    </svg>
  );
}

// ── BookCover — tries real image first, falls back to SVG ─────────────────────
function BookCover({ book, theme }) {
  const [imageError, setImageError] = React.useState(false);

  let bookData = { ...book };
  if (!bookData.isbn && typeof window !== 'undefined') {
    const storedIsbn = localStorage.getItem(`book_isbn_${book.id}`);
    if (storedIsbn) bookData.isbn = storedIsbn;
  }
  if (!bookData.coverUrl && typeof window !== 'undefined') {
    const storedUrl = localStorage.getItem(`book_cover_${book.id}`);
    if (storedUrl) bookData.coverUrl = storedUrl;
  }

  const coverUrl = getOpenLibraryCoverUrl(bookData);

  if (coverUrl && !imageError) {
    return (
      <img
        src={coverUrl}
        alt={book.title}
        className="book-cover-image"
        onError={() => setImageError(true)}
      />
    );
  }

  return (
    <BookCoverSVG
      title={book.title}
      author={book.author}
      category={book.category || 'Book'}
      accent={theme.accent}
      from={theme.from}
      to={theme.to}
      pattern={theme.pattern}
    />
  );
}

// ── BookCard ──────────────────────────────────────────────────────────────────
export default function BookCard({ book, onEdit, onDelete, onAddToCart, isAdmin, isLoggedIn }) {
  const [adding, setAdding] = useState(false);
  const [added,  setAdded]  = useState(false);

  const theme   = CATEGORY_THEMES[book.category] || DEFAULT_THEME;
  const inStock = book.stock > 0;

  const handleAddToCart = async () => {
    if (!onAddToCart || adding || added) return;
    setAdding(true);
    try {
      await onAddToCart(book);
      setAdded(true);
      setTimeout(() => setAdded(false), 2000);
    } catch {
      // error handled in parent
    } finally {
      setAdding(false);
    }
  };

  return (
    <div className="book-card fade-up">
      {/* Cover */}
      <div className="book-cover">
        <BookCover book={book} theme={theme} />
        {!inStock && (
          <div className="book-out-of-stock">Out of Stock</div>
        )}
      </div>

      {/* Info */}
      <div className="book-info">
        <h3 className="book-title">{book.title}</h3>
        <p className="book-author">by {book.author}</p>

        <div className="book-meta">
          <span className="book-price">&#8377;{book.price?.toFixed(2)}</span>
          <span className="book-stock" style={{ color: inStock ? 'var(--green)' : 'var(--red)' }}>
            {inStock ? `${book.stock} in stock` : 'Out of stock'}
          </span>
        </div>

        {/* Actions */}
        <div className="book-actions">
          <Link to={`/books/${book.id}`} className="btn btn-outline btn-xs">
            View
          </Link>

          {isLoggedIn && !isAdmin && inStock && (
            <button
              className={`btn btn-xs btn-cart ${added ? 'btn-cart-added' : ''}`}
              onClick={handleAddToCart}
              disabled={adding || added}
            >
              {adding ? (
                '...'
              ) : added ? (
                <>
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3">
                    <polyline points="20 6 9 17 4 12"/>
                  </svg>
                  Added
                </>
              ) : (
                <>
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/>
                    <path d="M1 1h4l2.68 13.39a2 2 0 001.99 1.61h9.72a2 2 0 001.98-1.72L23 6H6"/>
                  </svg>
                  Add to Cart
                </>
              )}
            </button>
          )}

          {isAdmin && (
            <>
              <button className="btn btn-ghost btn-xs" onClick={() => onEdit(book)}>
                Edit
              </button>
              <button className="btn btn-danger btn-xs" onClick={() => onDelete(book.id)}>
                Delete
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
